input.command:
kubectl -n elasticsearch patch statefulset es-cluster --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "file-realm",
      "secret": {
        "secretName": "es-file-realm-aggregate",
        "defaultMode": 420
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users",
      "subPath": "users",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/users_roles",
      "subPath": "users_roles",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "file-realm",
      "mountPath": "/usr/share/elasticsearch/config/roles.yml",
      "subPath": "roles.yml",
      "readOnly": true
    }
  }
]'
